// Description: Collects fleet-level ArgoCD sync and health metrics via Thanos Querier.
// Description: Queries argocd_app_info for application counts and argocd_app_sync_total for sync rates.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("openshift.thanos.host")
def token = hostProps.get("openshift.thanos.pass")
def port = hostProps.get("openshift.thanos.port") ?: "443"
def useSsl = (hostProps.get("openshift.thanos.ssl") ?: "true").toLowerCase() == "true"

def results = [
    "total_apps": 0,
    "synced_apps": 0,
    "out_of_sync_apps": 0,
    "healthy_apps": 0,
    "degraded_apps": 0,
    "sync_success_rate": 0,
    "sync_failure_rate": 0
]

if (!host || !token) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def executeQuery(String promql, String baseUrl, String token) {
    try {
        def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = conn.inputStream.text
            def json = new JsonSlurper().parseText(response)
            if (json.status == "success" && json.data?.result?.size() > 0) {
                def val = json.data.result[0].value[1]
                return val?.toString()?.isNumber() ? val : null
            }
        } else {
            System.err.println("Query failed: HTTP ${conn.responseCode} for: ${promql}")
        }
    } catch (Exception e) {
        System.err.println("Query error for ${promql}: ${e.message}")
    }
    return null
}

def metrics = [
    "total_apps": 'count(argocd_app_info) or vector(0)',
    "synced_apps": 'count(argocd_app_info{sync_status="Synced"}) or vector(0)',
    "out_of_sync_apps": 'count(argocd_app_info{sync_status="OutOfSync"}) or vector(0)',
    "healthy_apps": 'count(argocd_app_info{health_status="Healthy"}) or vector(0)',
    "degraded_apps": 'count(argocd_app_info{health_status="Degraded"}) or vector(0)',
    "sync_success_rate": 'sum(rate(argocd_app_sync_total{phase="Succeeded"}[5m])) or vector(0)',
    "sync_failure_rate": 'sum(rate(argocd_app_sync_total{phase="Failed"}[5m])) or vector(0)'
]

metrics.each { dp, query ->
    def val = executeQuery(query, baseUrl, token)
    results[dp] = val ?: results[dp]
}

results.each { k, v -> println("${k}:${v}") }
return 0
